import { useState, useContext } from "react";
import axios from "axios";
import Button from "react-bootstrap/Button";
import Form from "react-bootstrap/Form";
import "bootstrap/dist/css/bootstrap.min.css";
import UserContext from './context';

export default function Withdraw() {
  const [withdrawAmount, setWithdrawAmount] = useState("");
  const [pin, setPin] = useState("");
  const [successMessage, setSuccessMessage] = useState("");
  const { user, setUser } = useContext(UserContext);

  const handleSubmit = async (e) => {
    e.preventDefault();

    const amountToWithdraw = parseFloat(withdrawAmount);
    if (isNaN(amountToWithdraw) || amountToWithdraw <= 0) {
      alert("Please enter a valid withdrawal amount.");
      return;
    }

    if (pin.length !== 4) {
      alert("Transaction PIN must be 4 digits.");
      return;
    }

    try {
      const response = await axios.post("http://localhost:8080/api/users/withdraw", {
        amount: amountToWithdraw,
        pin: pin
      });

      setSuccessMessage(`Successfully withdrawn ₹${amountToWithdraw}. Your new balance is ₹${response.data.newBalance}.`);
      setUser({ ...user, amount: response.data.newBalance, transactions: response.data.transactions });
      setWithdrawAmount("");
      setPin("");
    } catch (error) {
      alert(error.response?.data?.message || "Withdrawal failed. Please try again.");
    }
  };

  if (!user) return <div className="container mt-5"><h3>Please login to withdraw money.</h3></div>;

  return (
    <div className="background">
      <h1 className="register-heading">Withdraw</h1>
      <div className="text-center mb-4">
        <h4>Current Balance: ₹{user.amount}</h4>
      </div>

      {successMessage && <div className="alert alert-success">{successMessage}</div>}

      <Form className="custom-form" onSubmit={handleSubmit}>
        <Form.Group className="mb-3 custom-form-group">
          <Form.Label className="custom-label">Amount</Form.Label>
          <Form.Control
            className="custom-input"
            type="number"
            placeholder="Enter withdrawal amount"
            value={withdrawAmount}
            onChange={(e) => setWithdrawAmount(e.target.value)}
          />
        </Form.Group>

        <Form.Group className="mb-3 custom-form-group">
          <Form.Label className="custom-label">Transaction PIN</Form.Label>
          <Form.Control
            className="custom-input"
            type="password"
            maxLength="4"
            placeholder="Enter 4-digit PIN"
            value={pin}
            onChange={(e) => setPin(e.target.value)}
          />
        </Form.Group>

        <Button className="custom-button" variant="primary" type="submit" disabled={!withdrawAmount || pin.length !== 4}>
          Withdraw
        </Button>
      </Form>
    </div>
  );
}
